const Q_BIOLOGY_2024_MODEL_I=[{"id": "objective>Biology>2024-Model-I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Non-living things</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">possess a high metabolic rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are able to respire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exhibit autotrophic nutrition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">show a low degree of organization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Non-living things lack the intricate and highly regulated structure found in living organisms. Their organization, if any, is minimal and does not support life processes.</div>", "topic": "NON LIVING THINGS"}, {"id": "objective>Biology>2024-Model-I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The smallest unit of classification is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kingdom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">genus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">class</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The species is the smallest and most specific unit of classification in the biological taxonomy. It is the fundamental category that groups individuals capable of interbreeding and producing fertile offspring. The classification hierarchy from broad to specific is typically: Kingdom, Phylum, Class, Order, Family, Genus, and Species, with species being the most specific and smallest unit.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>2024-Model-I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Procaryotic cells are found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">algae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protists</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spirogyra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monerans</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monerans, which include bacteria and archaea, are composed entirely of prokaryotic cells. Prokaryotic cells lack a true nucleus and membrane-bound organelles, which distinguishes them from eukaryotic cells found in organisms like algae, protists, and Spirogyra. Thus, Monerans are the group where prokaryotic cells are found.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>2024-Model-I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mycelium is a characteristics feature of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moulds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bacteria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mosses</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mycelium is a network of filamentous hyphae that is a characteristic feature of fungi, including moulds. It plays a crucial role in nutrient absorption and growth of the fungus. This extensive network allows the fungus to decompose and absorb organic material from its environment. Hence, mycelium is associated with moulds.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>2024-Model-I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mitochondrion is labelled by letter <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mitochondrion is oval or rod shaped. They are bounded by a double membrane. The inner membrane is folded and the interior is filled with matrix. It is describe as the power house of the cell.</div>", "topic": "CELL STRUCTURE AND FUNCTIONS"}, {"id": "objective>Biology>2024-Model-I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When is the best time to test for the presence of starch in a leaf</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Before sunrise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Immediately after sunrise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At midday</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At midnight</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Immediately after sunrise the plant has been exposed to light, allowing photosynthesis to occur and starch to accumulate in the leaves. This makes it an ideal time for testing the presence of starch, as it is when the starch levels are likely to be at their highest.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2024-Model-I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Food spoilage is mainly due to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">poor quality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high protein content</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the activities of decomposers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Food spoilage is mainly due to the activities of decomposers such as bacteria, fungi, and other microorganisms. These decomposers break down the organic compounds in food, resulting in changes in flavor, texture, and appearance that make the food unfit for consumption. While factors like water content, protein levels, and initial food quality can influence the rate of spoilage, the fundamental cause is the metabolic activities of decomposers.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2024-Model-I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these explains a community?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A group of organisms found in several habitats</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A group of populations found in several habitats</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A group of many populations of different species living in the same habitat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A group of populations of the same species living in the same habitat</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A community in biology is a group of interacting organisms of different species that share a common habitat or location. The interactions among the species in a community can involve symbiosis, predation, competition, or other ecological relationships. A community is a part of an ecosystem, which includes all the living and non-living components of the environment</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2024-Model-I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following elements is essential for the formation of chlorophyll in plants?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Phosphorus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Potassium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium is essential for the formation of chlorophyll, the green pigment in plants responsible for photosynthesis. Magnesium sits at the center of the chlorophyll molecule, allowing it to capture light energy. Nitrogen is important for proteins and nucleic acids, phosphorus is vital for energy transfer (ATP), and potassium helps regulate water balance in plants.</div>", "topic": "ECOLOGY"}, {"id": "objective>Biology>2024-Model-I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the diagram below, which is a decomposer? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bird</div>", "<div style=\"font-family:Cambria;font-size:17px;\">snake</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mushroom</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mushrooms are decomposers because like other fungi, they break down dead and decaying matter to make their own food. </div>", "topic": "ECOLOGY"}, {"id": "objective>Biology>2024-Model-I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Generally, food chains are short because of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">energy losses at each trophic level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the activity of decomposers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the activity of consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nutrient cycling</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Food chains are generally short because of energy losses at each trophic level. With only about 10% of energy being transferred from one level to the next, there is progressively less energy available to support organisms at higher trophic levels. This significant reduction in energy limits the number of levels that a food chain can sustain, making food chains relatively short.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>2024-Model-I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A constituent of the exhaust gases of motor vehicles which causes serious air pollution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water vapour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon dioxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon monoxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon monoxide (CO) is a constituent of motor vehicle exhaust gases that causes serious air pollution. It is a colorless, odorless gas that is highly toxic and can have severe health impacts. Unlike carbon dioxide, which contributes to long-term climate change, carbon monoxide poses immediate risks to human health and is a significant air pollutant in urban areas with high vehicle traffic.</div>", "topic": "POLLUTION"}, {"id": "objective>Biology>2024-Model-I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the organisms listed below is not a micro-organism?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Virus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rhizopus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tapeworm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plasmodium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tapeworms are not micro-organisms. They are large parasitic worms that can be seen without the aid of a microscope, distinguishing them from viruses, Rhizopus, and Plasmodium, all of which are microscopic organisms.</div>", "topic": "MICROORGANISMS"}, {"id": "objective>Biology>2024-Model-I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Micro-organisms are used in the production of many</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fossil fuels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">antibiotics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minerals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plastics</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Micro-organisms are widely used in the production of antibiotics. Through fermentation processes, specific strains of bacteria or fungi produce bioactive compounds that have antimicrobial properties. These antibiotics are crucial in medicine for treating bacterial infections and have saved countless lives since their discovery.</div>", "topic": "MICROORGANISMS"}, {"id": "objective>Biology>2024-Model-I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms are transmitted by houseflies?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Plasmodium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trypanosoma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vibro cholerae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gonococcus sp.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Houseflies can transmit Vibrio cholerae, the bacterium responsible for causing cholera. While houseflies do not directly cause the disease, they can carry the bacteria from contaminated sources to food and surfaces, facilitating the transmission of the disease to humans when contaminated food or water is ingested.</div>", "topic": "MICROORGANISMS"}, {"id": "objective>Biology>2024-Model-I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distribution of proteins and other materials throughout cell is the primary function of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">endoplasmic reticulum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ribosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lysosomes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The endoplasmic reticulum (ER) is involved in the synthesis, modification, and transport of proteins and other materials within the cell. It plays a significant role in intracellular transport and the movement of proteins to their proper destinations within the cell.</div>", "topic": "CELL STRUCTURE AND FUNCTIONS"}, {"id": "objective>Biology>2024-Model-I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process in which cell takes in solid materials by engulfing them is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pinocytosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">osmosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phagocytosis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process in which a cell takes in solid materials by engulfing them is called phagocytosis. This process is commonly observed in immune cells such as macrophages, which engulf and digest pathogens and cellular debris to protect the body from infection and maintain tissue homeostasis.</div>", "topic": "CELL PROPERTIES AND FUNCTION"}, {"id": "objective>Biology>2024-Model-I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cell is the functional unit of living organisms because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">multicellular organisms consist of cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all cells in a multicellular organism function as a single cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the function of a multicellular organism is the sum total of its constituent cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the function of a single cell is superior to that of the multicellular organism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cell is considered the functional unit of living organisms because the functions of multicellular organisms arise from the collective activities of their constituent cells. Each cell performs specialized functions that contribute to the overall functioning of the organism. Therefore, the function of a multicellular organism is the sum total of its constituent cells' activities.</div>", "topic": "CELL PROPERTIES AND FUNCTION"}, {"id": "objective>Biology>2024-Model-I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The importance of turgidity of the cells in herbaceous plants is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provides mechanical support for the plant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enables absorption of more water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enables the intake of mineral salts from the soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevents haemolysis of the cells</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The importance of turgidity of cells in herbaceous plants includes providing mechanical support for the plant by exerting pressure against the cell wall. Turgidity helps maintain the rigidity of plant tissues and prevents wilting, contributing to the overall health and stability of the plant.</div>", "topic": "CELL PROPERTIES AND FUNCTION"}, {"id": "objective>Biology>2024-Model-I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which body system is shown in the diagram? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">digestive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiratory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">circulatory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reproductive</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The digestive tract of humans starts with the mouth and ends with the anus. It includes different structures such as the mouth, oesophagus, pancreas, stomach, small intestine, large intestine, liver, gall bladder, and anus.</div>", "topic": "DIGESTIVE SYSTEM"}, {"id": "objective>Biology>2024-Model-I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Paramecium moves by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the whipping action of its flagellum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the co-ordinated beating of its cilia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rotating action of its flagella</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pushing out a jet of water</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Paramecium is a type of single-celled organism known as a ciliate, named for the cilia that cover its surface. Cilia are tiny hair-like structures that beat in a coordinated manner, allowing the Paramecium to move through water. This coordinated beating generates a rhythmic wave that propels the organism forward or backward. Unlike flagella, which are longer and typically fewer in number, cilia are numerous and shorter, and their synchronized movement is crucial for the locomotion of the Paramecium.</div>", "topic": "DIGESTIVE SYSTEM"}, {"id": "objective>Biology>2024-Model-I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What structure connects a skeletal muscle to a bone?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ligament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cartilage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Joint capsule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tendons</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A tendon is a tough, fibrous connective tissue that anchors muscle to bone. When muscles contract, tendons transmit the force to bones, causing movement. Ligaments connect bones to other bones, providing joint stability, while cartilage cushions joints. The joint capsule encloses a synovial joint but does not attach muscles to bones.</div>", "topic": "TISSUES AND SUPPORTING SYSTEM"}, {"id": "objective>Biology>2024-Model-I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the alimentary system of a bird where grinding of maize occurs is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">crop</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stomach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gizzard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rectum</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In birds, the gizzard is a specialized, muscular part of the alimentary canal that is responsible for grinding food. Birds often swallow small stones or grit, which accumulate in the gizzard and help in mechanically breaking down tough food items like maize. The crop is a storage pouch where food is softened, the stomach is where chemical digestion begins, and the rectum is involved in the expulsion of waste. The gizzard's strong muscles and ingested grit make it the primary site for the physical grinding of food.</div>", "topic": "DIGESTIVE SYSTEM"}, {"id": "objective>Biology>2024-Model-I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following processes takes place in the small intestine of a human being?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Swallowing of food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Secretion of saliva</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Absorption of digested food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Secretion of bile</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The small intestine is the part of the human digestive system where the majority of digestion and nutrient absorption occurs. After food is broken down in the stomach, it moves into the small intestine, where enzymes continue the digestive process. The walls of the small intestine are lined with villi and microvilli, which increase the surface area for absorption. Nutrients such as amino acids, simple sugars, and fatty acids are absorbed into the bloodstream through these structures.</div>", "topic": "DIGESTIVE SYSTEM"}, {"id": "objective>Biology>2024-Model-I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The vegetarian habit of the tadpole is associated with its possession of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">external gills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a streamlined body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a long coiled intestine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a large head with sucker</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The vegetarian diet of tadpoles is associated with their possession of a long coiled intestine. Herbivorous diets, which consist primarily of plant material, require more extensive digestion to break down the tough cell walls of plants. A long coiled intestine provides a larger surface area for the absorption of nutrients from plant matter. This adaptation is necessary for tadpoles to efficiently process their vegetarian diet and obtain the nutrients they need for growth and development.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2024-Model-I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which mammalian tooth is structurally adapted for tearing flesh?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Molar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Incisor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Canine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Premolar</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Canine teeth are structurally adapted for tearing flesh. They are long, pointed teeth located between the incisors and premolars. In carnivorous mammals, canines are well-developed and are used for gripping and tearing meat. Their sharp, conical shape allows them to puncture and hold onto prey effectively.</div>", "topic": "NUTRITION : ANIMAL NUTRITION~~NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>2024-Model-I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following adapts the aorta to the high pressure of blood from the heart?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Thick elastic wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rigid walls</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Membranes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Narrow lumen</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The aorta is the main artery that carries oxygenated blood from the heart to the rest of the body, and it must withstand the high pressure generated by the heart's contractions. To handle this high pressure, the aorta has a thick, elastic wall composed of layers of smooth muscle and elastic fibers. This elasticity allows the aorta to stretch and accommodate the surge of blood with each heartbeat, and then recoil to help propel the blood forward. This elasticity is crucial for maintaining a continuous and smooth flow of blood through the circulatory system.</div>", "topic": "TRANSPORT : NEED FOR TRANSPORTATION"}, {"id": "objective>Biology>2024-Model-I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bicuspid valve is located between</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">left auricle and left ventricle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">right auricle and right ventricle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">left and right auricles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">left and right ventricle</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bicuspid valve, also known as the mitral valve, is located between the left atrium (auricle) and the left ventricle in the heart. This valve ensures one-way blood flow from the left atrium to the left ventricle and prevents backflow when the left ventricle contracts and pumps blood into the aorta. The right side of the heart has a similar valve, the tricuspid valve, which is located between the right atrium and the right ventricle. Therefore, the bicuspid (mitral) valve is specifically situated between the left atrium and left ventricle.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2024-Model-I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cutaneous respiration is carried out by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">frogs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">snakes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">birds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mammals</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cutaneous respiration refers to the process of gas exchange through the skin. Frogs are known for their ability to carry out cutaneous respiration. They have moist, permeable skin that allows oxygen to diffuse directly into their bloodstream and carbon dioxide to diffuse out. This type of respiration is particularly important for frogs, especially when they are underwater or in environments where lung respiration is not sufficient.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>2024-Model-I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What stage of mitosis is most likely represented by the picture below? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">telophase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prophase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metaphase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anaphase</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Telophase is the final stage of mitosis. The sister chromosomes, once sister chromatids, have now been segregated to the far poles of the cell. The mitotic spindle is no longer necessary because the chromosomes completed their journey. The tubulin dimers fall apart, and much of the microtubule network is disassembled.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2024-Model-I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Air breathing vertebrates use</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tracheae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lungbooks</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Air-breathing vertebrates, such as mammals, birds, reptiles, and amphibians, use lungs for respiration. Lungs are specialized organs that facilitate the exchange of oxygen and carbon dioxide between the air and the bloodstream.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>2024-Model-I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organelle which eliminates water from the body of a protozoa is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">plasma membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contractile vacuole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protoplasm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In protozoa, the contractile vacuole is the organelle responsible for eliminating excess water from the cell. Protozoa often live in freshwater environments where water continuously enters the cell by osmosis. The contractile vacuole collects this excess water and expels it from the cell, thereby regulating the internal water balance and preventing the cell from bursting.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2024-Model-I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following parts of the mammalian skin is involved in excretion?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sebaceous gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sweat gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Horny layer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hair follicle</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sweat glands in mammalian skin are involved in excretion. They produce sweat, which contains water, salts, and small amounts of metabolic waste products such as urea and lactic acid. Through the process of sweating, these substances are excreted from the body, helping to regulate body temperature and remove waste products.</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>2024-Model-I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the correct sequence of movement of urea during urine formation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Glomerulus → Bowman's capsule → convoluted tubule → Henle's loop → collecting tubule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glomerulus→Henle's loop→convoluted tubule →collecting tubule→Bowman's capsule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glomerulus→Bowman's capsule →Henle's loop →convoluted tubule → collecting tubule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glomerulus→ Bowman's capsule →collecting tubule→Henle's loop → convoluted tubule </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During urine formation, the movement of urea follows a specific path through the nephron, the functional unit of the kidney. The correct sequence is: <br/>  <br/> Glomerulus: Blood is filtered in the glomerulus, where waste products, including urea, are filtered out of the blood. <br/> Bowman's capsule: The filtrate, including urea, enters Bowman's capsule from the glomerulus. <br/> Proximal convoluted tubule: The filtrate then moves into the proximal convoluted tubule, where some reabsorption and secretion occur. <br/> Henle's loop: The filtrate flows through the loop of Henle, which concentrates the urine and reabsorbs water and salts. <br/> Distal convoluted tubule: The filtrate then enters the distal convoluted tubule, where further reabsorption and secretion take place. <br/> Collecting tubule: Finally, the filtrate, now urine, moves into the collecting tubule, where it is transported to the renal pelvis and eventually to the bladder for excretion.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2024-Model-I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which term best describes the image shown? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">food web</div>", "<div style=\"font-family:Cambria;font-size:17px;\">life cycle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">food chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water cycle</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The life cycle of a butterfly consists of four stages: <br/> The egg: Winged adults lay eggs on the food plant that their caterpillars will feed on. <br/> The larva (caterpillar): The caterpillars hatch from the eggs and grow by eating the food plant. <br/> The pupa (chrysalis): When fully grown, the caterpillars form a protective case around themselves and undergo metamorphosis, a process of changing shape. <br/> The adult butterfly: The butterflies emerge from the chrysalis with wings and look for a mate. They have a short lifespan, usually less than a month.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2024-Model-I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following groups of organisms does excretion take place only by simple diffusion through the body surface?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Worms, toad and Amoeba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paramecium, grasshopper and snake</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Toad, insect and Euglena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paramecium, Amoeba and Euglena</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Excretion by simple diffusion through the body surface is a process typically found in single-celled organisms and some simple multicellular organisms. These organisms do not have specialized excretory systems and rely on diffusion to remove metabolic waste directly through their cell membranes. <br/>  <br/> Paramecium, Amoeba, and Euglena are all single-celled protozoans. They excrete waste products by simple diffusion across their cell membranes due to their small size and large surface area relative to their volume.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2024-Model-I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a characteristic feature of tropical rain forests?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Trees with longer boles (trunks) than those in savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fewer canopy strata than found in the savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Many more trees and climbers than in the savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trees are usually tall</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tropical rainforests are characterized by a complex structure with multiple canopy layers, or strata. These include the emergent layer, the main canopy, the understory, and the forest floor. This complex stratification is much more intricate than the structure found in savannas, which typically have fewer canopy layers due to the dominance of grasses and fewer trees.</div>", "topic": "HABITAT"}, {"id": "objective>Biology>2024-Model-I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Puddles, ponds, rivers, lakes, seas and oceans are grouped together as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ecosystem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marine habitat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aquatic habitat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biosphere</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Puddles, ponds, rivers, lakes, seas, and oceans are all bodies of water and are collectively referred to as aquatic habitats. These habitats can be further categorized into freshwater habitats (such as puddles, ponds, rivers, and lakes) and marine habitats (such as seas and oceans).</div>", "topic": "HABITAT"}, {"id": "objective>Biology>2024-Model-I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Few number of trees is characteristic of the Savanna zones of Nigeria because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is too much sunlight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is limited amount of rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are exposed to grazing animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are covered by mountains</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The savanna zones of Nigeria, like other savanna regions, are characterized by a climate with a distinct dry season and a wet season. The limited and seasonal rainfall is a primary factor that influences the vegetation structure, resulting in fewer trees and more grasses. Trees in savannas are often scattered and have adapted to survive in conditions with periodic water scarcity.</div>", "topic": "HABITAT"}, {"id": "objective>Biology>2024-Model-I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Succession is best described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a process whereby different organisms systematically colonize a barren habitat until a stable community is formed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a process whereby animals occupy a barren habitat until a suitable habitat is formed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a process whereby plants occupy a barren habitat until a suitable habitat is formed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the replacement of weaker plants and animals by the stronger ones</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ecological succession is the process through which a series of different communities (both plants and animals) gradually colonize an area, starting from a barren or disturbed habitat, and eventually leading to the formation of a stable, mature community, known as a climax community. This process involves changes in the species composition and ecosystem structure over time, driven by interactions among species and environmental conditions.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}];
